const staticData = $getWorkflowStaticData('global');
const sinceToken = staticData.matrixSinceToken || '';
return [{ json: { sinceToken, ...$('Gateway Config').first().json } }];

const config = $('Gateway Config').first().json;
const syncData = $input.first().json;
const staticData = $getWorkflowStaticData('global');

// Save sync token for next poll
if (syncData.next_batch) staticData.matrixSinceToken = syncData.next_batch;

// Extract messages from timeline
const roomId = config.MATRIX_ROOM_ID;
const rooms = syncData.rooms?.join || {};
const room = rooms[roomId] || syncData.rooms?.join?.[Object.keys(syncData.rooms?.join || {})[0]];
const events = room?.timeline?.events || [];

const lastTs = staticData.lastProcessedTimestamp || 0;
const botUser = config.MATRIX_BOT_USER;

const messages = events
  .filter(e => e.type === 'm.room.message'
    && e.sender !== botUser
    && e.origin_server_ts > lastTs)
  .map(e => ({
    messageText: e.content?.body || '',
    sender: e.sender,
    timestamp: e.origin_server_ts
  }));

if (messages.length > 0) {
  staticData.lastProcessedTimestamp = Math.max(...messages.map(m => m.timestamp));
}

return messages.length > 0
  ? [{ json: { ...messages[0], ...config } }]
  : [];

const config = $('Gateway Config').first().json;
const messageText = $input.first().json.messageText || '';
const trimmed = messageText.trim();
const lower = trimmed.toLowerCase();
const base64Message = Buffer.from(messageText).toString('base64');

// Check for PREFIX: message format (e.g. PROJ-4: do something)
const prefixMatch = trimmed.match(/^([A-Z]+-\d+):\s*([\s\S]*)$/);
if (prefixMatch) {
  const prefix = prefixMatch[1];
  const strippedText = prefixMatch[2].trim();
  if (!strippedText) {
    return [{ json: { ...config, command: 'empty', matrixBody: JSON.stringify({ msgtype: 'm.notice', body: 'Message body is empty. Usage: ' + prefix + ': <your message>' }) } }];
  }
  const base64Stripped = Buffer.from(strippedText).toString('base64');
  return [{ json: { ...config, command: 'message', sub: '', args: [], messageText: strippedText, base64Message: base64Stripped, prefix } }];
}

if (!lower.startsWith('!')) {
  if (!trimmed) return [{ json: { ...config, command: 'empty', matrixBody: JSON.stringify({ msgtype: 'm.notice', body: 'Message cannot be empty.' }) } }];
  return [{ json: { ...config, command: 'message', sub: '', args: [], messageText, base64Message, prefix: '' } }];
}

const lowerParts = lower.slice(1).split(/\s+/);
const origParts = trimmed.slice(1).split(/\s+/);
const command = lowerParts[0] || '';
const sub = lowerParts[1] || '';
const args = origParts.slice(2);

// Legacy aliases
const resolved = { done: 'session', cancel: 'session', status: 'session' }[command] || command;
const resolvedSub = { done: 'done', cancel: 'cancel', status: 'current' }[command] || sub;

return [{ json: { ...config, command: resolved, sub: resolvedSub, args, messageText, base64Message, prefix: '' } }];

const config = $('Gateway Config').first().json;
const stdout = $input.first().json.stdout || '';
const stderr = $input.first().json.stderr || '';
const output = (stdout.trim() || stderr.trim());

if (output === 'NO_SESSION') {
  const body = 'No active Claude session. Start one via YouTrack or !issue start <id>.';
  return [{ json: { matrixBody: JSON.stringify({ msgtype: 'm.notice', body }), ...config } }];
}

let result;
try {
  const parsed = JSON.parse(output);
  result = parsed.result || output.substring(0, 4000);
} catch(e) {
  result = output.substring(0, 4000) || 'No response from Claude.';
}

const body = result;
const matrixBody = JSON.stringify({ msgtype: 'm.text', body });
return [{ json: { matrixBody, ...config } }];

const config = $('Gateway Config').first().json;
const stdout = $input.first().json.stdout || '';
const sub = $('Detect Command').first().json.sub || 'current';
const output = stdout.trim();
let body = '';

if (sub === 'current') {
  const raw = output.replace('SESSION:', '');
  if (!raw || raw === 'NO_SESSION') body = 'No active session.';
  else {
    try {
      const s = JSON.parse(raw);
      body = 'Current session:\nIssue: ' + s.issue_id + '\nMessages: ' + s.message_count + '\nPaused: ' + (s.paused ? 'Yes' : 'No');
    } catch(e) { body = 'Error: ' + raw.substring(0, 200); }
  }
} else if (sub === 'list') {
  try {
    const rows = JSON.parse(output || '[]');
    body = rows.length ? rows.map((s, i) => (i+1) + '. ' + s.issue_id + (s.is_current ? ' (current)' : '')).join('\n') : 'No active sessions.';
  } catch(e) { body = 'Error: ' + output.substring(0, 200); }
} else if (sub === 'done') {
  if (!output) body = 'No active session to end.';
  else {
    try { const s = JSON.parse(output); body = s.session_id ? 'Ending session for ' + s.issue_id + '...' : 'No active session.'; } catch(e) { body = 'No active session.'; }
  }
} else if (sub === 'cancel') {
  body = output.startsWith('CANCELLED:') ? 'Session ' + output.split(':')[1] + ' cancelled.' : output === 'NO_SESSION' ? 'No session to cancel.' : output;
} else if (sub === 'pause') {
  body = output.startsWith('PAUSED:') ? 'Session ' + output.split(':')[1] + ' paused.' : output === 'NO_SESSION' ? 'No session to pause.' : output;
} else if (sub === 'resume') {
  body = output.startsWith('RESUMED:') ? 'Session ' + output.split(':')[1] + ' resumed.' : output === 'NO_SESSION' ? 'No session to resume.' : output;
} else { body = 'Unknown: ' + sub; }

const matrixBody = JSON.stringify({ msgtype: 'm.notice', body });
return [{ json: { matrixBody, ...config } }];

const config = $('Gateway Config').first().json;
const stdout = $input.first().json.stdout || '';
const output = stdout.trim();
let body = '';

try {
  const data = JSON.parse(output);
  if (Array.isArray(data)) {
    body = data.length === 0 ? 'No issues in progress.' : data.map(i => i.idReadable + ': ' + (i.summary || '—')).join('\n');
  } else if (data.idReadable) {
    body = data.idReadable + ': ' + (data.summary || '—') + '\n' + (data.description || 'No description').substring(0, 500);
  } else { body = output.substring(0, 1000); }
} catch(e) { body = output || 'No response from YouTrack.'; }

const matrixBody = JSON.stringify({ msgtype: 'm.notice', body });
return [{ json: { matrixBody, ...config } }];

const config = $('Gateway Config').first().json;
const output = ($input.first().json.stdout || '').trim();
const body = output || 'No pipeline data available.';
const matrixBody = JSON.stringify({ msgtype: 'm.notice', body });
return [{ json: { matrixBody, ...config } }];

const config = $('Gateway Config').first().json;
const output = ($input.first().json.stdout || '').trim();
const body = output || 'No system data.';
const matrixBody = JSON.stringify({ msgtype: 'm.notice', body });
return [{ json: { matrixBody, ...config } }];

const config = $('Gateway Config').first().json;
if ($json.matrixBody) return [{ json: { matrixBody: $json.matrixBody, ...config } }];
const body = 'Unknown command: !' + ($json.command || 'unknown') + '\nType !help to see available commands.';
const matrixBody = JSON.stringify({ msgtype: 'm.notice', body });
return [{ json: { matrixBody, ...config } }];
